#include <stdio.h>
#include <pthread.h>

void* thread_function(void* arg) {
  printf("Thread işləyir: %s\n", (char*)arg);
  return NULL;
}

int main() {
  pthread_t thread1, thread2;
  char* msg1 = "Birinci thread";
  char* msg2 = "İkinci thread";

  pthread_create(&thread1, NULL, thread_function, (void*)msg1);
  pthread_create(&thread2, NULL, thread_function, (void*)msg2);

  pthread_join(thread1, NULL);
  pthread_join(thread2, NULL);

  printf("Bütün thread-lər tamamlandı\n");
  return 0;
}
// Output (sıra dəyişə bilər):
// Thread işləyir: Birinci thread
// Thread işləyir: İkinci thread
// Bütün thread-lər tamamlandı

#include <stdio.h>
#include <pthread.h>

int counter = 0;

void* increment_counter(void* arg) {
  for (int i = 0; i < 100000; i++) {
    counter++; // Yarış vəziyyəti
  }
  return NULL;
}

int main() {
  pthread_t thread1, thread2;

  pthread_create(&thread1, NULL, increment_counter, NULL);
  pthread_create(&thread2, NULL, increment_counter, NULL);

  pthread_join(thread1, NULL);
  pthread_join(thread2, NULL);

  printf("Counter: %d\n", counter);
  return 0;
}
// Output (səhv ola bilər):
// Counter: [200000-dən kiçik bir dəyər, məsələn, 198732]

#include <stdio.h>
#include <pthread.h>

int counter = 0;
pthread_mutex_t lock;

void* increment_counter(void* arg) {
  for (int i = 0; i < 100000; i++) {
    pthread_mutex_lock(&lock);
    counter++;
    pthread_mutex_lock(&lock);
  }
  return NULL;
}

int main() {
  pthread_t thread1, thread2;
  pthread_mutex_init(&lock, NULL);

  pthread_create(&thread1, NULL, increment_counter, NULL);
  pthread_create(&thread2, NULL, increment_counter, NULL);

  pthread_join(thread1, NULL);
  pthread_join(thread2, NULL);

  pthread_mutex_destroy(&lock);
  printf("Counter: %d\n", counter);
  return 0;
}
// Output:
// Counter: 200000

#include <stdio.h>
#include <pthread.h>

int shared_value = 0;

void* add_to_value(void* arg) {
  for (int i = 0; i < 100000; i++) {
    shared_value++; // Yarış vəziyyəti
  }
  return NULL;
}

int main() {
  pthread_t thread1, thread2;

  pthread_create(&thread1, NULL, add_to_value, NULL);
  pthread_create(&thread2, NULL, add_to_value, NULL);

  pthread_join(thread1, NULL);
  pthread_join(thread2, NULL);

  printf("Shared value: %d\n", shared_value);
  return 0;
}
// Output (səhv ola bilər):
// Shared value: [200000-dən kiçik bir dəyər]

